// GetWin32PerfFormattedDataHvStatsHyperVHypervisorRootVirtualProcessor returns the Win32_PerfFormattedData_HvStats_HyperVHypervisorRootVirtualProcessor instance identified by its key
// properties, or wmi.ErrNotFound.
func GetWin32PerfFormattedDataHvStatsHyperVHypervisorRootVirtualProcessor(svc *wmi.Service, name string) (*Win32PerfFormattedDataHvStatsHyperVHypervisorRootVirtualProcessor, error) {
	where := "Name = " + wmi.WQLValue(name)
	out, err := QueryWin32PerfFormattedDataHvStatsHyperVHypervisorRootVirtualProcessor(svc, where)
	if err != nil {
		return nil, err
	}
	if len(out) == 0 {
		return nil, wmi.ErrNotFound
	}
	return &out[0], nil
}

