// GetWin32PerfRawDataHvStatsHyperVHypervisorRootVirtualProcessor returns the Win32_PerfRawData_HvStats_HyperVHypervisorRootVirtualProcessor instance identified by its key
// properties, or wmi.ErrNotFound.
func GetWin32PerfRawDataHvStatsHyperVHypervisorRootVirtualProcessor(svc *wmi.Service, name string) (*Win32PerfRawDataHvStatsHyperVHypervisorRootVirtualProcessor, error) {
	where := "Name = " + wmi.WQLValue(name)
	out, err := QueryWin32PerfRawDataHvStatsHyperVHypervisorRootVirtualProcessor(svc, where)
	if err != nil {
		return nil, err
	}
	if len(out) == 0 {
		return nil, wmi.ErrNotFound
	}
	return &out[0], nil
}

// QueryWin32PerfRawDataHvStatsHyperVHypervisorVirtualProcessor runs the WQL query against the class and decodes each
// instance into a Win32PerfRawDataHvStatsHyperVHypervisorVirtualProcessor. Pass the WHERE clause (or "" for all).
