// GetWin32PingStatus returns the Win32_PingStatus instance identified by its key
// properties, or wmi.ErrNotFound.
func GetWin32PingStatus(svc *wmi.Service, address string, bufferSize uint32, noFragmentation bool, recordRoute uint32, resolveAddressNames bool, sourceRoute string, sourceRouteType uint32, timeToLive uint32, timeout uint32, timestampRoute uint32, typeofService uint32) (*Win32PingStatus, error) {
	where := "Address = " + wmi.WQLValue(address) +
		" AND " + "BufferSize = " + wmi.WQLValue(bufferSize) +
		" AND " + "NoFragmentation = " + wmi.WQLValue(noFragmentation) +
		" AND " + "RecordRoute = " + wmi.WQLValue(recordRoute) +
		" AND " + "ResolveAddressNames = " + wmi.WQLValue(resolveAddressNames) +
		" AND " + "SourceRoute = " + wmi.WQLValue(sourceRoute) +
		" AND " + "SourceRouteType = " + wmi.WQLValue(sourceRouteType) +
		" AND " + "TimeToLive = " + wmi.WQLValue(timeToLive) +
		" AND " + "Timeout = " + wmi.WQLValue(timeout) +
		" AND " + "TimestampRoute = " + wmi.WQLValue(timestampRoute) +
		" AND " + "TypeofService = " + wmi.WQLValue(typeofService)
	out, err := QueryWin32PingStatus(svc, where)
	if err != nil {
		return nil, err
	}
	if len(out) == 0 {
		return nil, wmi.ErrNotFound
	}
	return &out[0], nil
}

